export function initAircraftShapes() {
    // eslint-disable-next-line no-console
    console.log('%c[INIT] AircraftIcons: legacy initAircraftShapes() skipped (V13 active)', 'color:#607D8B');
}

// Pre-warm on load
initAircraftIcons();

/**
 * Resolves the best available AIRCRAFT_CATALOG key for a given typecode + category.
 * Mirrors getAircraftImage's priority chain but returns the string key instead of an image.
 * Used by MapView.jsx to feed vectorPathsMap without calling getAircraftImage twice.
 */
export function resolveTypecodeKey(typecode, category) {
    const type = (typecode || '').toString().trim().toUpperCase();

    // 1. Exact / fuzzy catalog match (prefix alias etc.)
    const matched = getBestLocalMatch(type);
    if (matched) return matched;

    // 2. Pattern-based category inference
    let catName = detectCategory(type);
    if (!catName) {
        if (category === 7)                         catName = 'HELI';
        else if (category === 5 || category === 6)  catName = 'WIDE';
        else if (category === 3 || category === 4)  catName = 'NARROW';
        else if (category === 1 || category === 2)  catName = 'LIGHT';
    }
    if (catName && CATEGORY_FALLBACK[catName]) return CATEGORY_FALLBACK[catName];

    // 3. Absolute default — guaranteed to exist in AIRCRAFT_CATALOG
    return CATEGORY_FALLBACK.DEFAULT;
}

/**
 * Returns the category string (JUMBO/WIDE/NARROW/REGIONAL/LIGHT/HELI/MILITARY/UNKNOWN)
 * for a plane object. Used by MapView to apply per-category user scale.
 */
export function getAircraftCategory(plane) {
    const type = (typeof plane === 'string' ? plane : (plane._activeTypecode || plane.typecode || '')).toString().trim().toUpperCase();
    const category = typeof plane === 'string' ? null : plane.category;

    // 1. Exact catalog match — use entry's cat
    const matched = getBestLocalMatch(type);
    if (matched && AIRCRAFT_CATALOG[matched]?.cat) return AIRCRAFT_CATALOG[matched].cat;

    // 2. Pattern inference
    let catName = detectCategory(type);
    if (!catName) {
        if (category === 7)                        catName = 'HELI';
        else if (category === 5 || category === 6) catName = 'WIDE';
        else if (category === 3 || category === 4) catName = 'NARROW';
        else if (category === 1 || category === 2) catName = 'LIGHT';
    }
    return catName || 'UNKNOWN';
}

/**
 * Legacy scale helper.
 */
export function getAircraftScale(plane) {
    const type = typeof plane === 'string' ? plane : (plane._activeTypecode || plane.typecode);
    const cat = typeof plane === 'string' ? null : plane.category;
    const data = getAircraftImage(type, cat);
    return data.scale || 1.0;
}

// Increment this when scale values or size curve changes — busts MapView scaleCacheRef
export const ICON_SCALE_VERSION = 4;

/**
 * adsb.fi-style zoom-to-pixel curve with compressed category scaling.
 *
 * Tier 1 — Tactical Dot (zoom ≤ 4):  5 px  ← render loop draws arc(), NOT Path2D
 * Tier 2 — Small silhouette (z 5-8): 9-26 px
 * Tier 3 — Full silhouette  (z 9+):  30+ px, capped at 58 px
 *
 * `typeScale` is the raw SVG normalization factor from AIRCRAFT_CATALOG.
 * We apply power-curve compression so narrow-body vs wide-body differs by
 * only ~12% (adsb.fi reference), not 30%+ as with linear multiplication.
 *
 * Reference: B738 / A320 → catalog scale ≈ 1.45 → renders at 1.00× base.
 * Compression formula: base × REF × (typeScale / REF)^0.45
 *   LIGHT/HELI (1.00) → 0.84×  e.g. zoom9 → 37px
 *   NARROW     (1.45) → 1.00×  e.g. zoom9 → 44px  ← reference
 *   WIDE       (1.89) → 1.12×  e.g. zoom9 → 49px  (+12%)
 *   JUMBO B744 (1.88) → 1.12×  e.g. zoom9 → 49px
 *   JUMBO A380 (2.33) → 1.22×  e.g. zoom9 → 54px  (+23%)
 *   A225       (2.58) → 1.28×  e.g. zoom9 → 56px  (+27%)
 */
const _SCALE_REF = 1.45; // B738 / A320 catalog scale — rendered as 1× base
export function getDrawSize(_plane, zoom, _typeScale = 1.0) {
    let base;
    if      (zoom <= 4)  base = 5;
    else if (zoom <= 5)  base = 9;
    else if (zoom <= 6)  base = 15;
    else if (zoom <= 7)  base = 21;
    else if (zoom <= 8)  base = 26;
    else if (zoom <= 9)  base = 30;
    else if (zoom <= 10) base = 34;
    else if (zoom <= 11) base = 38;
    else if (zoom <= 12) base = 42;
    else if (zoom <= 13) base = 46;
    else                 base = Math.min(58, 46 + (zoom - 13) * 4);

    // Uniform size: all aircraft render at the same pixel size per zoom level.
    return Math.round(base * _SCALE_REF);
}


// ── Dynamic RexKramer1 GitHub SVG Loader ─────────────────────────────────────
// Fetches 1:1 exact aircraft shapes from the AircraftShapesSVG repo.
// ALL fetch logic lives here — the animate() loop only calls getDynamicImage()
// which is O(1) Map lookup, zero async, zero GC.
//
// Lifecycle:
//   1. prewarmExactSvg(typecode)  ← call when typecode first becomes known
//   2. getDynamicImage(tc, sel)   ← sync getter inside animate loop
//
const exactImageCache = new Map(); // tc → { normal: Image, selected: Image } | null
const _ghPending = new Map(); // tc → Promise (dedup in-flight requests)
// Use local backend to serve SVGs — avoids GitHub CDN 404s and rate limits
const _GH_BASE   = '/api/svg/';

// Persist known-missing typecodes in localStorage so they are never re-requested
// after a page refresh. Key includes a version stamp to auto-invalidate on SVG repo updates.
const _SVG_MISS_KEY = 'aerostrat_svg_miss_v1';
try {
    const stored = JSON.parse(localStorage.getItem(_SVG_MISS_KEY) || '[]');
    stored.forEach(tc => exactImageCache.set(tc, null));
} catch (_) {}
function _persistMiss(tc) {
    try {
        const stored = JSON.parse(localStorage.getItem(_SVG_MISS_KEY) || '[]');
        if (!stored.includes(tc)) {
            stored.push(tc);
            localStorage.setItem(_SVG_MISS_KEY, JSON.stringify(stored));
        }
    } catch (_) {}
}

function _buildGhImage(svgText, color, isSelected = false) {
    // Strip any existing fill/stroke attributes (except fill="none" for outlines)
    // then inject a CSS rule that forces all fill to our desired color.
    // adsb.fi style: white outline with drop-shadow for visibility on dark maps.
    const stripped = svgText
        .replace(/\s(?:fill|stroke|stroke-width|paint-order)="(?!none)[^"]*"/gi, '');
    const strokeColor = isSelected ? '#00ffff' : 'rgba(255,255,255,0.92)';
    const styled = stripped.replace(
        '</svg>',
        `<style>
            path,polygon,circle,rect,polyline,ellipse{
                fill:${color} !important;
                stroke:${strokeColor} !important;
                stroke-width:1.0 !important;
                stroke-linejoin:round !important;
                paint-order:stroke fill !important;
            }
        </style></svg>`
    );
    const url = `data:image/svg+xml;charset=utf-8,${encodeURIComponent(styled)}`;
    const img = new Image();
    img.src = url;
    return img;
}

/**
 * Pre-warm the GitHub SVG for a typecode.
 * Safe to call multiple times — deduplication is handled internally.
 * MUST NOT be called inside the animate() loop.
 */
export function prewarmExactSvg(typecode) {
    if (!typecode) return;
    const tc = typecode.toUpperCase();
    if (exactImageCache.has(tc) || _ghPending.has(tc)) return;

    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 6000);

    const p = fetch(`${_GH_BASE}${tc}.svg`, { signal: controller.signal })
        .then(r => {
            clearTimeout(timeout);
            if (!r.ok) return null;
            return r.text();
        })
        .then(text => {
            if (!text || text.length < 80 || /<Error|<!DOCTYPE/i.test(text)) {
                exactImageCache.set(tc, null);
                _persistMiss(tc); // remember across page refreshes
                return;
            }
            exactImageCache.set(tc, {
                normal:   _buildGhImage(text, '#ffce00', false),
                selected: _buildGhImage(text, '#00ffff', true),
            });
        })
        .catch(() => { clearTimeout(timeout); exactImageCache.set(tc, null); _persistMiss(tc); })
        .finally(() => _ghPending.delete(tc));

    _ghPending.set(tc, p);
}

/**
 * Synchronous getter for a pre-loaded GitHub SVG image.
 * Returns null if not yet available or typecode is absent from the repo.
 * Called inside the 60-fps animate() loop — must be O(1).
 */
export function getDynamicImage(typecode, isSelected = false) {
    if (!typecode) return null;
    const entry = exactImageCache.get(typecode.toUpperCase());
    if (!entry) return null;
    return isSelected ? entry.selected : entry.normal;
}

/**
 * Returns true if the SVG was fetched but does NOT exist in the RexKramer1 repo.
 * Distinguishes "not tried yet / still loading" (undefined) from "tried and missing" (null).
 */
export function isSvgUnavailable(typecode) {
    if (!typecode) return true;
    const tc = typecode.toUpperCase();
    return exactImageCache.has(tc) && exactImageCache.get(tc) === null;
}

export { AIRCRAFT_CATALOG as paths };
